	"packageManager": "bun@1.3.5",
	"workspaces": [
		"apps/*",
		"packages/*"
	],
	"overrides": {
		"@chkit/core": "0.1.0-beta.5",
		"@chkit/clickhouse": "0.1.0-beta.5"
	}
}

